+
+  grid_map_msgs::GridMap msg;
+  grid_map::GridMapRosConverter::toMessage(gridMap, msg);
+  gridMapPub.publish(msg);
+
+
+  // run
+  ros::spin();
+  return EXIT_SUCCESS;
+}

