+      break;
+    case 5:  // Central cell height value not valid. Not a problem.
+      distanceX = 2 * gridMapResolution_;
+      break;
+    case 3:  // Bottom cell height value not valid.
+      bottomCell = centralCell;
+      distanceX = gridMapResolution_;
