+GridMap GridMap::getSubmap(const Eigen::Vector2d& position, const Eigen::Array2d& length, Eigen::Array2i& indexInSubmap, bool& isSuccess)
+{
+  // Submap the generate.
+  GridMap submap(types_);
+  submap.setClearTypes(clearTypes_);
